document.addEventListener("DOMContentLoaded",function(){const t=document.querySelector(".menu-toggle"),n=document.querySelector(".main-nav");t&&n&&t.addEventListener("click",function(){const e=this.getAttribute("aria-expanded")==="true";this.setAttribute("aria-expanded",!e),n.classList.toggle("is-open")}),document.querySelectorAll('a[href^="#"]').forEach(e=>{e.addEventListener("click",function(e){e.preventDefault();const t=document.querySelector(this.getAttribute("href"));t&&t.scrollIntoView({behavior:"smooth"})})});const e=document.querySelector(".site-header");e&&window.addEventListener("scroll",function(){window.scrollY>10?e.classList.add("is-scrolled"):e.classList.remove("is-scrolled")})})